import{_ as a,o as r,c as o,ag as d,ah as e}from"./chunks/framework.D9bIGSBm.js";const b=JSON.parse('{"title":"模型供应商","description":"","frontmatter":{},"headers":[],"relativePath":"settings/providers.md","filePath":"settings/providers.md"}'),n={name:"settings/providers.md"};function i(h,t,s,l,p,c){return r(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="模型供应商" tabindex="-1">模型供应商 <a class="header-anchor" href="#模型供应商" aria-label="Permalink to &quot;模型供应商&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>模型供应商</strong></p><p>模型供应商功能让你在不使用 Claude/Codex 官方账号的情况下，通过第三方 API 或自建代理接入模型服务。配置供应商后，可在任务选择器栏中选择对应的模型档位，调用该供应商提供的模型。</p><hr><h2 id="供应商类型" tabindex="-1">供应商类型 <a class="header-anchor" href="#供应商类型" aria-label="Permalink to &quot;供应商类型&quot;">​</a></h2><p>应用将供应商分为三类：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>原生（OAuth）</strong></td><td>Claude OAuth 与 Codex OAuth，凭据由 CLI 自身登录管理，应用仅管理模型清单与上下文窗口配置</td></tr><tr><td><strong>内置</strong></td><td>预置的第三方平台，开箱即用，填入 API Key 即可</td></tr><tr><td><strong>自定义</strong></td><td>手动填写接口地址与 API Key，适用于任意 OpenAI/Anthropic 兼容代理</td></tr></tbody></table><hr><h2 id="内置供应商" tabindex="-1">内置供应商 <a class="header-anchor" href="#内置供应商" aria-label="Permalink to &quot;内置供应商&quot;">​</a></h2><p>应用预置了以下 8 家第三方平台，无需手动填写接口地址，直接输入 API Key 即可启用：</p><table tabindex="0"><thead><tr><th>供应商名称</th><th>说明</th></tr></thead><tbody><tr><td>deepseek</td><td>DeepSeek 平台，支持 Anthropic 与 OpenAI 双接口</td></tr><tr><td>z.ai</td><td>智谱 z.ai 平台，仅 Anthropic 接口</td></tr><tr><td>bigmodel</td><td>智谱 BigModel 平台，支持 Anthropic 与 OpenAI 双接口</td></tr><tr><td>openrouter</td><td>OpenRouter 聚合平台，支持 Anthropic 与 OpenAI 双接口</td></tr><tr><td>moonshot</td><td>月之暗面 Kimi 平台，支持 Anthropic 与 OpenAI 双接口</td></tr><tr><td>minimax</td><td>MiniMax 平台，支持 Anthropic 与 OpenAI 双接口</td></tr><tr><td>mimo</td><td>小米 Mimo 平台，仅 Anthropic 接口</td></tr><tr><td>Qwen</td><td>阿里云通义千问平台，支持 Anthropic 与 OpenAI 双接口</td></tr></tbody></table><hr><h2 id="供应商可用性" tabindex="-1">供应商可用性 <a class="header-anchor" href="#供应商可用性" aria-label="Permalink to &quot;供应商可用性&quot;">​</a></h2><p>每个供应商面板右侧会显示两个可用性指示标记：</p><ul><li><strong>Claude CLI 可用</strong> — 当 Anthropic 接口地址非空时显示</li><li><strong>Codex CLI 可用</strong> — 当 OpenAI 接口地址非空时显示</li></ul><p>仅支持单接口的供应商（如 z.ai、mimo）只对相应 CLI 可用。</p><hr><h2 id="配置供应商" tabindex="-1">配置供应商 <a class="header-anchor" href="#配置供应商" aria-label="Permalink to &quot;配置供应商&quot;">​</a></h2><p><img src="'+e+'" alt="模型供应商页面，左侧供应商列表，右侧显示选中供应商的 API Key、接口地址、模型映射等配置字段"></p><h3 id="_1-选择供应商" tabindex="-1">1. 选择供应商 <a class="header-anchor" href="#_1-选择供应商" aria-label="Permalink to &quot;1. 选择供应商&quot;">​</a></h3><p>在左侧供应商列表中点击要配置的供应商名称，右侧显示详情面板。</p><h3 id="_2-填写-api-key" tabindex="-1">2. 填写 API Key <a class="header-anchor" href="#_2-填写-api-key" aria-label="Permalink to &quot;2. 填写 API Key&quot;">​</a></h3><p>在 <strong>API Key</strong> 输入框中粘贴从对应平台获取的密钥。</p><div class="warning custom-block"><p class="custom-block-title">请妥善保管 API Key</p><p>API Key 是访问模型服务的唯一凭据，泄露后可能导致费用损失或数据风险。不要将 API Key 截图分享、写入版本库，或通过不安全渠道传输。</p></div><h3 id="_3-配置接口地址-可选" tabindex="-1">3. 配置接口地址（可选） <a class="header-anchor" href="#_3-配置接口地址-可选" aria-label="Permalink to &quot;3. 配置接口地址（可选）&quot;">​</a></h3><p>内置供应商已预填接口地址，通常无需修改。若平台更换域名或你使用私有部署版本，可在以下字段中修改：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>Anthropic 接口地址</strong></td><td>用于 Claude CLI；支持 Anthropic 消息格式的接口根地址</td></tr><tr><td><strong>OpenAI 接口地址</strong></td><td>用于 Codex CLI；支持 OpenAI Chat Completion 格式的接口根地址</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>两个接口地址不能同时为空，否则保存时会提示错误。</p></div><h3 id="_4-配置模型映射" tabindex="-1">4. 配置模型映射 <a class="header-anchor" href="#_4-配置模型映射" aria-label="Permalink to &quot;4. 配置模型映射&quot;">​</a></h3><p>模型映射将应用的三个档位槽（<strong>Opus</strong>、<strong>Sonnet</strong>、<strong>Haiku</strong>）与供应商实际提供的模型名称对应起来。</p><table tabindex="0"><thead><tr><th>档位</th><th>对应角色</th></tr></thead><tbody><tr><td>Opus</td><td>复杂任务</td></tr><tr><td>Sonnet</td><td>常规任务</td></tr><tr><td>Haiku</td><td>轻量任务</td></tr></tbody></table><p>在每个档位的下拉列表中选择想要绑定的具体模型。若某档位留空（显示&quot;未设置&quot;），则该档位在此供应商下不可用。</p><h3 id="_5-配置上下文窗口-可选" tabindex="-1">5. 配置上下文窗口（可选） <a class="header-anchor" href="#_5-配置上下文窗口-可选" aria-label="Permalink to &quot;5. 配置上下文窗口（可选）&quot;">​</a></h3><p><strong>上下文窗口</strong>字段允许手动指定模型支持的 Token 数量上限，用于上下文使用率显示与自动压缩触发判断。留空则使用应用内置的默认值（v0.5.2 起出厂预设了主流模型的默认值；未匹配到的模型回退到 200,000 Token）。</p><hr><h2 id="添加自定义供应商" tabindex="-1">添加自定义供应商 <a class="header-anchor" href="#添加自定义供应商" aria-label="Permalink to &quot;添加自定义供应商&quot;">​</a></h2><p>若你的目标平台不在内置列表中（例如自建 OpenAI 兼容代理），可添加自定义供应商：</p><ol><li>点击左侧供应商列表底部的&quot;添加&quot;按钮，列表中出现名为<strong>新供应商</strong>的条目。</li><li>点击名称旁的编辑（铅笔）图标，输入供应商的显示名称。</li><li>按 <a href="#配置供应商">配置供应商</a> 步骤填写接口地址、API Key 与模型映射。</li></ol><p>自定义供应商可通过列表底部的删除按钮移除（需二次确认）；内置供应商与 OAuth 供应商不可删除。</p><hr><h2 id="codex-内置中转" tabindex="-1">Codex 内置中转 <a class="header-anchor" href="#codex-内置中转" aria-label="Permalink to &quot;Codex 内置中转&quot;">​</a></h2><p>若已安装 Codex CLI，部分支持 OpenAI 接口的供应商会出现<strong>经内置中转使用（Codex）</strong> 开关。开启后，Codex CLI 的请求将经由应用内置的协议转换中转（Chat Completion → Response Stream）后转发至该供应商，从而让 Codex CLI 使用非官方接口。</p><hr><h2 id="供应商列表截图" tabindex="-1">供应商列表截图 <a class="header-anchor" href="#供应商列表截图" aria-label="Permalink to &quot;供应商列表截图&quot;">​</a></h2><p><img src="'+e+'" alt="模型供应商页面，左侧展示 Claude OAuth、Codex OAuth 及 8 家内置供应商列表，右侧为选中供应商的详细配置区域"></p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/dependencies.html">依赖管理</a> — 安装或更新 Claude CLI / Codex CLI</li><li><a href="/docs/settings/mcp.html">MCP 服务器</a> — 配置模型上下文协议服务器以扩展工具能力</li></ul>',48)])])}const g=a(n,[["render",i]]);export{b as __pageData,g as default};
